    "modules.dev_demo_step5": "5. Start backend på nytt og test",
    "modules.dev_demo_note": "Det er alt — ingen redigering av main.py, ingen registerimport, ingen migrasjon. Modulinnlasteren oppdager mappen, leser manifestet og monterer ruteren. Modulen vises også automatisk under Moduler og markedsplass.",
    "modules.dev_what": "Hva er en modul?",
    "modules.dev_what_desc": "OpenConstructionERP v4.3 leveres med 110+ moduler. Alle forretningsfunksjoner — BOQ, BIM Hub, Fremdrift, CDE, regionale BOQ-pakker, AI-verktøy — er selvstendige moduler. En modul kan legge til REST-ruter, databasetabeller, UI-sider, valideringsregler, oversettelser eller en kombinasjon. Du kan aktivere, deaktivere, installere eller erstatte enhver modul uten å berøre kjernen.",
    "modules.dev_what_backend": "Kun backend",
    "modules.dev_what_backend_ex": "f.eks. en ny API-kobling eller webhook-mottaker",
    "modules.dev_what_frontend": "Kun frontend",
    "modules.dev_what_frontend_ex": "f.eks. et regionalt BOQ-utvekslings-UI eller en nisje-rapport",
    "modules.dev_what_full": "Full stack",
    "modules.dev_what_full_ex": "de fleste reelle funksjoner — ruter, UI og en DB-migrasjon",
    "modules.dev_backend_title": "Backend-modul — på 5 minutter",
    "modules.dev_backend_intro": "Alt starter fra malen i repoet. Modulinnlasteren oppdager automatisk alt du legger i backend/app/modules/ — ingen manuell kobling av ruter eller migrasjoner.",
    "modules.dev_step_copy": "Stillasmonter fra malen",
    "modules.dev_step_manifest": "Rediger manifestet",
    "modules.dev_step_router": "Legg til en ruter",
