    "modules.dev_backend_ref": "Referanseimplementasjoner: backend/app/modules/boq/ og backend/app/modules/projects/.",
    "modules.dev_tree_title": "Filstruktur — hva hører hvor",
    "modules.dev_tree_intro": "Både backend- og frontend-moduler følger en streng konvensjon. Følg den, og innlasteren + registeret kobler alt opp; avvik og ting feiler på overraskende steder.",
    "modules.dev_tree_backend": "Backend-modul",
    "modules.dev_tree_frontend": "Frontend-modul",
    "modules.dev_tree_note": "Alle filer unntatt manifest.* er valgfrie — start med det minste settet og legg til filer etter hvert som modulen vokser.",
    "modules.dev_db_title": "Databasemigrasjoner",
    "modules.dev_db_intro": "Hvis modulen din legger til eller endrer tabeller, må du levere en migrasjon. Prosjektet bruker Alembic — autogenerer er din venn, men gjennomgå alltid resultatet.",
    "modules.dev_db_step1": "Definer modellen din",
