    "modules.dev_events_title": "Hendelser og kroker — hvordan moduler kommuniserer",
    "modules.dev_events_intro": "Importer aldri direkte fra en annen modul. Send hendelser og abonner på dem. Dette holder moduler frakoblet og gjør installasjon/deaktivering trygt.",
    "modules.dev_events_publish": "Publiser en hendelse",
